import re
import random
from collections import Counter

# Replace with your LLM call
def llm(prompt: str) -> str:
    raise NotImplementedError

CHOICE_RE = re.compile(r"\b([A-E])\b", re.I)

def extract_choice(text: str):
    m = CHOICE_RE.search(text.strip())
    return m.group(1).upper() if m else None

def direct_prompt(q, choices):
    return f"Answer the multiple-choice question. Output ONLY the final letter.\nQ: {q}\nChoices: {choices}\nFinal letter:"

def draft_cot_prompt(q, choices):
    return (
        "Solve with a SHORT chain of thought of 4-6 numbered steps. "
        "Each step must be a single atomic claim. Then output ONLY the final letter on the last line as 'Final: X'.\n"
        f"Q: {q}\nChoices: {choices}\n"
    )

def extract_steps(cot_text: str):
    # crude extraction of lines starting with digit.
    steps = []
    for line in cot_text.splitlines():
        line = line.strip()
        if re.match(r"^\d+\.", line):
            steps.append(re.sub(r"^\d+\.\s*", "", line))
    return steps

def extract_final(cot_text: str):
    m = re.search(r"Final\s*:\s*([A-E])\b", cot_text, re.I)
    return m.group(1).upper() if m else extract_choice(cot_text)

def claimify_prompt(steps):
    joined = "\n".join(f"{i+1}. {s}" for i, s in enumerate(steps))
    return (
        "Rewrite each step into a concise checkable claim (no extra reasoning). "
        "Output as a numbered list of claims, one per line.\n"
        f"Steps:\n{joined}\nClaims:"
    )

def parse_numbered_list(text: str):
    items = []
    for line in text.splitlines():
        line = line.strip()
        if re.match(r"^\d+\.", line):
            items.append(re.sub(r"^\d+\.\s*", "", line))
    return items

def evidence_prompt(q, claims, m=6):
    cl = "\n".join(f"- {c}" for c in claims)
    return (
        f"Generate {m} short commonsense/science evidence statements that would help verify the claims for the question. "
        "Each evidence must be 1 sentence, and you must not mention answer letters.\n"
        f"Question: {q}\nClaims:\n{cl}\n\nEvidence (numbered 1..{m}):"
    )

def parse_evidence(text: str):
    ev = []
    for line in text.splitlines():
        line = line.strip()
        if re.match(r"^\d+\.", line):
            ev.append(re.sub(r"^\d+\.\s*", "", line))
    return ev

def coverage_prompt(claims, evidence):
    cl = "\n".join(f"{i+1}. {c}" for i, c in enumerate(claims))
    ev = "\n".join(f"{i+1}. {e}" for i, e in enumerate(evidence))
    return (
        "For each claim, decide if it is SUPPORTED, CONTRADICTED, or NOT-ENOUGH-INFO using ONLY the evidence. "
        "Output one line per claim: i) LABEL (evidence_id or '-')\n"
        f"Claims:\n{cl}\n\nEvidence:\n{ev}\n\nJudgments:"
    )

def parse_judgments(text: str, n_claims: int):
    labels = ["NOT-ENOUGH-INFO"] * n_claims
    cited = [None] * n_claims
    for line in text.splitlines():
        line = line.strip()
        m = re.match(r"^(\d+)\)\s*(SUPPORTED|CONTRADICTED|NOT-ENOUGH-INFO)\s*(?:\((\d+)\)|\((-)\))?", line, re.I)
        if m:
            i = int(m.group(1)) - 1
            if 0 <= i < n_claims:
                labels[i] = m.group(2).upper()
                cited[i] = None if m.group(4) == "-" else (int(m.group(3)) if m.group(3) else None)
    return labels, cited

def self_consistency_answer(q, choices, n=5):
    ans = [extract_choice(llm(direct_prompt(q, choices))) for _ in range(n)]
    ans = [a for a in ans if a]
    if not ans:
        return None, 0.0
    c = Counter(ans)
    top, cnt = c.most_common(1)[0]
    return top, cnt / len(ans)

def minimal_repair_prompt(q, choices, claims, evidence, labels):
    cl = "\n".join(f"{i+1}. {c} [{labels[i]}]" for i, c in enumerate(claims))
    ev = "\n".join(f"{i+1}. {e}" for i, e in enumerate(evidence))
    return (
        "You must revise the reasoning by REMOVING or EDITING only claims that are CONTRADICTED or NOT-ENOUGH-INFO. "
        "Then answer in <=3 steps, and each step must cite an evidence id like [E2]. "
        "Finally output ONLY 'Final: X'.\n"
        f"Q: {q}\nChoices: {choices}\n\nClaims with labels:\n{cl}\n\nEvidence:\n{ev}\n"
    )

def ec_cot(q, choices, m=6, n_sc=5, cov_tau=0.6):
    draft = llm(draft_cot_prompt(q, choices))
    steps = extract_steps(draft)
    draft_ans = extract_final(draft)

    if not steps:
        # fallback
        a, stab = self_consistency_answer(q, choices, n=n_sc)
        return a, {"route": "fallback", "coverage": 0.0, "stability": stab}

    claims = parse_numbered_list(llm(claimify_prompt(steps)))
    claims = claims[:6] if claims else steps[:6]

    evidence = parse_evidence(llm(evidence_prompt(q, claims, m=m)))
    evidence = evidence[:m]

    judg = llm(coverage_prompt(claims, evidence))
    labels, _ = parse_judgments(judg, len(claims))

    supported = sum(1 for x in labels if x == "SUPPORTED")
    contrad = any(x == "CONTRADICTED" for x in labels)
    coverage = supported / max(1, len(claims))

    sc_ans, stability = self_consistency_answer(q, choices, n=n_sc)

    # Trigger minimal repair when under-supported or contradicted
    if coverage < cov_tau or contrad:
        repaired = llm(minimal_repair_prompt(q, choices, claims, evidence, labels))
        rep_ans = extract_final(repaired)
        # prefer repaired only if it aligns with stability or increases stability proxy
        if rep_ans and (rep_ans == sc_ans or stability < 0.6):
            return rep_ans, {"route": "repair", "coverage": coverage, "stability": stability}

    # otherwise keep stable answer if present, else draft
    out = sc_ans if sc_ans else draft_ans
    return out, {"route": "no_repair", "coverage": coverage, "stability": stability}

